// console.log 版：外面接不到
function add(num1, num2) {
  console.log(num1 + num2);
}
let result = add(2, 3);
console.log(result);

// return 版：外面可以接住
function add(num1, num2) {
  return num1 + num2;
}
let result = add(2, 3);
console.log(result);

function getGrade(score) {
  if (score >= 90) return "A";
  if (score >= 80) return "B";
  if (score >= 70) return "C";
  return "D";
}

console.log(getGrade(95));
console.log(getGrade(72));

// 第一步：直接寫（只能用一次）
let num = 4;
if (num % 2 === 0) {
  console.log("偶數");
} else {
  console.log("奇數");
}

// 第三步：function + return（可重複用，結果可帶走）
function checkEven(num) {
  if (num % 2 === 0) {
    return "偶數";
  }
  return "奇數";
}
let result = checkEven(4);
console.log(result);

let count = 0;

function addOne() {
  let localVar = "我是區域";
  count += 1;
}

addOne();
addOne();
console.log(count);

// 傳統函式宣告
function add(a, b) {
  return a + b;
}
console.log(add(2, 3));

// 箭頭函式寫法
const add = (a, b) => a + b;
console.log(add(2, 3));

// 只有一個參數，可以省略小括號
const double = n => n * 2;
console.log(double(4));

// 多行邏輯，需要大括號和 return
const getGrade = score => {
  if (score >= 60) return "及格";
  return "不及格";
};
console.log(getGrade(75));

// 純函式：同樣輸入，同樣輸出
function add(a, b) {
  return a + b;
}

console.log(add(1, 2));
console.log(add(1, 2));

// 不純的函式：修改了外部變數
let total = 0;

function addToTotal(n) {
  total += n; // 改了外部變數（副作用）
  return total;
}

console.log(addToTotal(5));
console.log(addToTotal(5));

